  "inlineSchema": "datasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\nenum Role {\n  SUPER_ADMIN\n  OWNER\n  MANAGER\n  CASHIER\n  WAITER\n  KITCHEN\n}\n\nenum OrderStatus {\n  PENDING\n  PREPARING\n  READY\n  SERVED\n  SETTLED\n  CANCELLED\n}\n\nenum PaymentMethod {\n  CASH\n  FONEPAY\n  CARD\n  CREDIT\n}\n\nmodel Tenant {\n  id         String     @id @default(uuid())\n  name       String\n  phone      String\n  address    String\n  panNumber  String? // Mandatory for Nepalese business compliance\n  vatRate    Decimal    @default(13.00) @db.Decimal(5, 2)\n  scRate     Decimal    @default(0.00) @db.Decimal(5, 2) // Service charge percentage\n  isActive   Boolean    @default(true)\n  createdAt  DateTime   @default(now())\n  updatedAt  DateTime   @updatedAt\n  users      User[]\n  categories Category[]\n  menuItems  MenuItem[]\n  tables     Table[]\n  orders     Order[]\n  bills      Bill[]\n  auditLogs  AuditLog[]\n\n  @@map(\"tenants\")\n}\n\nmodel User {\n  id           String     @id @default(uuid())\n  restaurantId String\n  tenant       Tenant     @relation(fields: [restaurantId], references: [id], onDelete: Cascade)\n  name         String\n  phone        String     @unique\n  passwordHash String\n  pinHash      String // 4-digit PIN for waiter/cashier screen resume\n  role         Role\n  isActive     Boolean    @default(true)\n  createdAt    DateTime   @default(now())\n  updatedAt    DateTime   @updatedAt\n  orders       Order[]    @relation(\"WaiterOrders\")\n  bills        Bill[]     @relation(\"CashierBills\")\n  auditLogs    AuditLog[]\n\n  @@index([restaurantId])\n  @@map(\"users\")\n}\n\nmodel Category {\n  id           String     @id @default(uuid())\n  restaurantId String\n  tenant       Tenant     @relation(fields: [restaurantId], references: [id], onDelete: Cascade)\n  name         String\n  sortOrder    Int        @default(0)\n  isDeleted    Boolean    @default(false)\n  createdAt    DateTime   @default(now())\n  updatedAt    DateTime   @updatedAt\n  menuItems    MenuItem[]\n\n  @@unique([restaurantId, name])\n  @@index([restaurantId])\n  @@map(\"categories\")\n}\n\nmodel MenuItem {\n  id           String             @id @default(uuid())\n  restaurantId String\n  tenant       Tenant             @relation(fields: [restaurantId], references: [id], onDelete: Cascade)\n  categoryId   String\n  category     Category           @relation(fields: [categoryId], references: [id])\n  name         String\n  description  String?\n  price        Decimal            @db.Decimal(10, 2)\n  isVeg        Boolean            @default(false)\n  imageUrl     String?\n  isAvailable  Boolean            @default(true)\n  isDeleted    Boolean            @default(false)\n  createdAt    DateTime           @default(now())\n  updatedAt    DateTime           @updatedAt\n  orderItems   OrderItem[]\n  modifiers    MenuItemModifier[]\n\n  @@index([restaurantId])\n  @@index([categoryId])\n  @@map(\"menu_items\")\n}\n\nmodel MenuItemModifier {\n  id          String   @id @default(uuid())\n  menuItemId  String\n  menuItem    MenuItem @relation(fields: [menuItemId], references: [id], onDelete: Cascade)\n  name        String // e.g., \"Extra Cheese\"\n  price       Decimal  @db.Decimal(10, 2)\n  isAvailable Boolean  @default(true)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  @@map(\"menu_item_modifiers\")\n}\n\nmodel Table {\n  id           String   @id @default(uuid())\n  restaurantId String\n  tenant       Tenant   @relation(fields: [restaurantId], references: [id], onDelete: Cascade)\n  tableNumber  String // e.g., \"1A\", \"Bar-3\"\n  capacity     Int\n  section      String // e.g., \"Main Floor\", \"Rooftop\"\n  status       String   @default(\"FREE\") // FREE, OCCUPIED, BILLING, DIRTY\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n  orders       Order[]\n\n  @@unique([restaurantId, tableNumber])\n  @@index([restaurantId])\n  @@map(\"tables\")\n}\n\nmodel Order {\n  id           String      @id @default(uuid()) // UUID generated client-side for sync tracking\n  restaurantId String\n  tenant       Tenant      @relation(fields: [restaurantId], references: [id], onDelete: Cascade)\n  tableId      String\n  table        Table       @relation(fields: [tableId], references: [id])\n  waiterId     String\n  waiter       User        @relation(\"WaiterOrders\", fields: [waiterId], references: [id])\n  status       OrderStatus @default(PENDING)\n  notes        String?\n  subtotal     Decimal     @db.Decimal(10, 2)\n  version      Int         @default(1) // For sync concurrency conflict checks\n  createdAt    DateTime    @default(now())\n  updatedAt    DateTime    @updatedAt\n  orderItems   OrderItem[]\n  bills        Bill[]\n\n  @@index([restaurantId])\n  @@index([tableId])\n  @@index([waiterId])\n  @@map(\"orders\")\n}\n\nmodel OrderItem {\n  id         String   @id @default(uuid())\n  orderId    String\n  order      Order    @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  menuItemId String\n  menuItem   MenuItem @relation(fields: [menuItemId], references: [id])\n  quantity   Int\n  unitPrice  Decimal  @db.Decimal(10, 2)\n  notes      String? // Custom customer notes (e.g., \"No onions\")\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n\n  @@index([orderId])\n  @@map(\"order_items\")\n}\n\nmodel Bill {\n  id             String        @id @default(uuid())\n  restaurantId   String\n  tenant         Tenant        @relation(fields: [restaurantId], references: [id], onDelete: Cascade)\n  orderId        String\n  order          Order         @relation(fields: [orderId], references: [id])\n  cashierId      String\n  cashier        User          @relation(\"CashierBills\", fields: [cashierId], references: [id])\n  billNumber     String // Sequentially generated per-tenant string (e.g., \"INV-2026-0001\")\n  subtotal       Decimal       @db.Decimal(10, 2)\n  discountAmount Decimal       @default(0.00) @db.Decimal(10, 2)\n  serviceCharge  Decimal       @db.Decimal(10, 2)\n  vatAmount      Decimal       @db.Decimal(10, 2)\n  grandTotal     Decimal       @db.Decimal(10, 2)\n  paymentMethod  PaymentMethod\n  paymentStatus  String        @default(\"PAID\") // PAID, REFUNDED\n  createdAt      DateTime      @default(now())\n  updatedAt      DateTime      @updatedAt\n\n  @@unique([restaurantId, billNumber])\n  @@index([restaurantId])\n  @@index([orderId])\n  @@map(\"bills\")\n}\n\nmodel AuditLog {\n  id           String   @id @default(uuid())\n  restaurantId String\n  tenant       Tenant   @relation(fields: [restaurantId], references: [id], onDelete: Cascade)\n  userId       String\n  user         User     @relation(fields: [userId], references: [id])\n  action       String // e.g., \"CANCEL_ORDER\", \"DELETE_MENU_ITEM\", \"APPLY_DISCOUNT\"\n  entityName   String // e.g., \"Order\", \"MenuItem\"\n  entityId     String\n  oldValues    Json?\n  newValues    Json?\n  ipAddress    String?\n  createdAt    DateTime @default(now())\n\n  @@index([restaurantId])\n  @@index([userId])\n  @@map(\"audit_logs\")\n}\n",
